function findDiagonalOrder(nums) {
    const diagonals = {};
    const m = nums.length;
    const res = [];

    for (let i = 0; i < m; i++) {
        for (let j = 0; j < nums[i].length; j++) {
            if (!diagonals[i + j]) {
                diagonals[i + j] = [];
            }
            diagonals[i + j].push(nums[i][j]);
        }
    }

    for (const key in diagonals) {
        res.push(...diagonals[key].reverse());
    }

    return res;
}
